UPDATE aiInfra.training_jobs SET created_at = '2026-01-05 21:49:26.075', updated_at = '2026-01-29 00:25:53.853', deleted_at = '2026-01-29 00:25:53.859', display_name = '3', user_id = 1, namespace = 'hmz', cluster_id = 1, framework_type = 'MPI', image_id = 5, startup_command = 'mpirun -np 2 -H ${MPI_HOSTS} python -c "
import tensorflow as tf
import socket
import os

hostname = socket.gethostname()
rank = int(os.environ.get(\'OMPI_COMM_WORLD_RANK\', 0))

print(f\'[{hostname}] Rank {rank} - Starting training...\')

# 创建简单模型
model = tf.keras.Sequential([
    tf.keras.layers.Dense(128, activation=\'relu\', input_shape=(784,)),
    tf.keras.layers.Dense(10, activation=\'softmax\')
])
model.compile(optimizer=\'adam\', loss=\'sparse_categorical_crossentropy\', metrics=[\'accuracy\'])

# 生成随机数据模拟训练
import numpy as np
x_train = np.random.random((1000, 784))
y_train = np.random.randint(0, 10, (1000,))

# 训练 3 个 epoch
model.fit(x_train, y_train, epochs=3, batch_size=32, verbose=1)

print(f\'[{hostname}] Rank {rank} - Training completed!\')
"', total_gpu_count = 0, gpu_type = '', resource_id = 3, worker_count = 2, master_cpu = 1, master_memory = 1, worker_cpu = 1, worker_memory = 1, worker_gpu = 0, use_shm = 1, shm_size = 2, k8s_job_uid = '9f2a47c1-3c34-4e47-bbdb-35d4f8278405', job_name = 'training-f5ce5b', status = 'KILLED', error_msg = '', started_at = '2026-01-05 21:49:29.249', finished_at = '2026-01-05 21:50:52.842', enable_tensorboard = 0, tensorboard_log_path = 'logs', tensorboard_id = 0, pay_type = 1, price = 1.0000, order_id = null, product_id = null, instance_count = 1, schedule_strategy = 'BALANCED' WHERE id = 30;
